import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';

const RegisterPage = ({ setUser }) => {
  const [form, setForm] = useState({ name: '', email: '', password: '', selectedCharityId: '', charityContributionPercent: 10 });
  const [charities, setCharities] = useState([]);
  const [error, setError] = useState('');
  const navigate = useNavigate();

  useEffect(() => {
    axios.get('/charities').then(({ data }) => setCharities(data));
  }, []);

  const change = (e) => setForm({ ...form, [e.target.name]: e.target.value });

  const submit = async (e) => {
    e.preventDefault();
    try {
      const { data } = await axios.post('/auth/register', form);
      setUser(data);
      navigate('/dashboard');
    } catch (err) {
      setError(err.response?.data?.message || 'Registration failed');
    }
  };

  return (
    <div style={{maxWidth:'400px', margin:'0 auto', padding:'20px'}}>
      <h2>Register</h2>
      {error && <p style={{ color: 'red' }}>{error}</p>}
      <form onSubmit={submit}>
        <label>Name</label>
        <input name='name' value={form.name} onChange={change} required />
        <label>Email</label>
        <input name='email' type='email' value={form.email} onChange={change} required />
        <label>Password</label>
        <input name='password' type='password' value={form.password} onChange={change} required />
        <label>Charity</label>
        <select name='selectedCharityId' value={form.selectedCharityId} onChange={change} required>
          <option value=''>Select Charity</option>
          {charities.map(c => <option key={c._id} value={c._id}>{c.name}</option>)}
        </select>
        <label>Contribution % (min 10)</label>
        <input name='charityContributionPercent' type='number' min='10' max='100' value={form.charityContributionPercent} onChange={change} required />
        <button type='submit'>Register</button>
      </form>
    </div>
  );
};

export default RegisterPage;
